parameters.jsCode:
const body = $input.first().json.body ?? $input.first().json;
let rca;
try { rca = typeof body.rca === 'string' ? JSON.parse(body.rca) : (body.rca ?? body); } catch(e) { rca = body; }

const dateStr = new Date().toISOString().split('T')[0];
const title = `[${dateStr}] Postmortem: ${rca.incident_id ?? 'INC-UNKNOWN'} — ${rca.incident_title ?? 'Incident'}`;

const timelineTable = (rca.timeline ?? []).map(t => `| ${t.time} | ${t.event} |`).join('\n');
const immediateList = (rca.immediate_actions ?? []).map((a, i) => `- [x] ${a}`).join('\n');
const remediationList = (rca.remediation_steps ?? []).map((s, i) => `- [ ] ${s}`).join('\n');
const preventionList = (rca.prevention ?? []).map((p, i) => `- [ ] ${p}`).join('\n');
const factorsList = (rca.contributing_factors ?? []).map(f => `- ${f}`).join('\n');

const markdown = `# ${title}

## Overview
| Field | Value |
|-------|-------|
| **Incident ID** | ${rca.incident_id ?? 'N/A'} |
| **Service** | ${rca.service ?? 'N/A'} |
| **Severity** | ${rca.severity ?? 'N/A'} |
| **Date** | ${dateStr} |
| **Est. MTTR** | ${rca.estimated_mttr_minutes ?? '?'} minutes |

## Impact
${rca.impact ?? 'Not assessed'}

## Root Cause
${rca.root_cause ?? 'Under investigation'}

## Contributing Factors
${factorsList || '- None identified'}

## Timeline
| Time | Event |
|------|-------|
${timelineTable || '| T-0 | Incident detected |'}

## Immediate Actions Taken
${immediateList || '- Manual review performed'}

## Remediation Steps
${remediationList || '- No steps defined'}

## Prevention / Long-term Fixes
${preventionList || '- No prevention steps defined'}

---
*Generated automatically by AI-Ops Watchdog at ${new Date().toISOString()}*
`;

return [{ json: { rca, title, markdown, incident_id: rca.incident_id, service: rca.service, severity: rca.severity } }];

